106:     private static void throwIfLoginModuleIsNotAllowed(AppConfigurationEntry appConfigurationEntry) {
107:         Set<String> disallowedLoginModuleList = Arrays.stream(
108:                 System.getProperty(DISALLOWED_LOGIN_MODULES_CONFIG, DISALLOWED_LOGIN_MODULES_DEFAULT).split(","))
109:                 .map(String::trim)
110:                 .collect(Collectors.toSet());
111:         String loginModuleName = appConfigurationEntry.getLoginModuleName().trim();
112:         if (disallowedLoginModuleList.contains(loginModuleName)) {
113:             throw new IllegalArgumentException(loginModuleName + " is not allowed. Update System property '"
114:                     + DISALLOWED_LOGIN_MODULES_CONFIG + "' to allow " + loginModuleName);
115:         }
116:     }
